import { mkdir, readFile, writeFile } from "node:fs/promises";
import { dirname, resolve } from "node:path";
import { fileURLToPath } from "node:url";

const repoRoot = resolve(dirname(fileURLToPath(import.meta.url)), "..");
const sourcePath = process.env.STOCK_TOOL_SOURCE ?? resolve(repoRoot, "../../financial-tools/stock_cost_calculator.html");
const targetPath = resolve(repoRoot, "public/tools/stock-cost-calculator/index.html");

const source = await readFile(sourcePath, "utf8");
const notice = [
  "<!--",
  "  Generated by npm run sync:stock-tool.",
  "  Source: local financial-tools/stock_cost_calculator.html",
  "  Do not edit this published copy directly.",
  "-->",
  ""
].join("\n");

await mkdir(dirname(targetPath), { recursive: true });
await writeFile(targetPath, notice + source, "utf8");
console.log(`Synced stock calculator to ${targetPath}`);
